              <div key={i} style={{ background:"#fff", border:"1px solid #D7E2D4", borderRadius:"14px", padding:"18px 18px 16px", boxShadow:"0 8px 24px rgba(18,45,88,.06)" }}>
                <div style={{ fontSize:"12px", fontWeight:700, letterSpacing:"1.2px", textTransform:"uppercase", color:"#3A7D2C", marginBottom:"8px" }}>{title}</div>
                <p style={{ margin:0, color:"#243849", fontSize:"14px", lineHeight:1.6 }}>{text}</p>
              </div>
